import { BoardEntity } from '../../../board-entity';
import { CardIds } from '../../../services/card-ids';
import { OnMinionKilledInput } from '../../../simulation/attack';
import { modifyStats } from '../../../simulation/stats';
import { OnMinionKilledCard } from '../../card.interface';

export const IcesnarlTheMighty: OnMinionKilledCard = {
	cardIds: [CardIds.IcesnarlTheMighty_BG20_HERO_100_Buddy, CardIds.IcesnarlTheMighty_BG20_HERO_100_Buddy_G],
	onMinionKilled: (
		minion: BoardEntity,
		input: OnMinionKilledInput,
	): { dmgDoneByAttacker: number; dmgDoneByDefender: number } => {
		if (input.killer.friendly !== input.minionKilled.friendly) {
			const mult = minion.cardId === CardIds.IcesnarlTheMighty_BG20_HERO_100_Buddy_G ? 2 : 1;
			// Can't be revived
			// 33.6 https://replays.firestoneapp.com/?reviewId=608ddffb-6c04-4def-a8de-fd39228f4de4&turn=11&action=4
			// Maybe should move to an "after kill" phase, where dead minions are already dead?
			// UPDATE 2026-03-20: it can in fact be revived
			// https://replays.firestoneapp.com/?reviewId=4d4af580-abf2-4223-8f44-ce6db06f82ce&turn=5&action=5
			// UPDATE 2026-03-20: and it triggers before the "attack immediately", so moving this to onMinionKill might be ok
			// .filter((e) => e.health > 0 && !e.definitelyDead)
			modifyStats(minion, minion, 0, 3 * mult, input.attackingBoard, input.attackingHero, input.gameState);
		}
		return { dmgDoneByAttacker: 0, dmgDoneByDefender: 0 };
	},
};
